import { AIProjectsClient } from "@azure/ai-projects";
import { DefaultAzureCredential } from "@azure/identity";

const credential = new DefaultAzureCredential();
const client = new AIProjectsClient(
    "https://your-project.openai.azure.com/",
    credential,
    { apiVersion: "2024-10-21" }
);

const thread = await client.threads.create({
    messages: [{
        role: "user",
        content: "Write product announcement for new AI platform"
    }]
});
console.log(`Thread ID: ${thread.id}`);

const run = await client.runs.create(thread.id, {
    assistant_id: "content-generation-agent",
    instructions: "Follow AP style guide, 500 words, optimistic tone"
});

const stream = client.runs.stream(thread.id, run.id);
for await (const event of stream) {
    if (event.type === "thread.message.delta") {
        process.stdout.write(event.data.content[0].text?.value || "");
    }
}

