from vex_sdk import VexClient, Guardrail

vex = VexClient(api_key="your-vex-api-key")

# Define brand voice guardrail
guardrail = Guardrail.create(
    name="brand-voice-check",
    checks=[
        {
            "type": "semantic_similarity",
            "model": "text-embedding-3-large",
            "reference_texts": [
                "Our brand voice is professional, optimistic, and enterprise-focused..."
            ],
            "threshold": 0.85
        }
    ]
)

# Validate agent output
def validate_content(agent_output: str) -> dict:
    result = vex.evaluate(
        guardrail.id,
        inputs={"content": agent_output}
    )
    return {
        "passes": result.passes,
        "score": result.metrics.similarity_score,
        "feedback": result.explanation
    }

def fact_check_content(content: str, citations: list) -> dict:
    fact_rail = Guardrail.get("enterprise-fact-check")

    result = vex.evaluate(
        fact_rail.id,
        inputs={
            "content": content,
            "citations": citations,
            "sources": ["internal-wiki.azure.com", "company-reports"]
        }
    )

    if not result.passes:
        return {
            "action": "revise",
            "issues": result.failing_checks,
            "suggestions": result.remediation
        }
    return {"status": "approved"}

import { VexClient } from "vex-sdk";

const vex = new VexClient({ apiKey: "your-vex-key" });

// Monitor token usage in real-time
const tokenGuardrail = await vex.guardrails.get("token-limit-monitor");

export async function checkTokenUsage(content: string, tokensUsed: number): Promise<boolean> {
    const maxTokens = 128000; // Agent thread limit

    const result = await vex.evaluate(tokenGuardrail.id, {
        content,
        current_tokens: tokensUsed,
        max_tokens: maxTokens,
        action: tokensUsed > maxTokens * 0.9 ? "summarize" : "continue"
    });

    if (result.decision === "truncate") {
        console.log("Token limit approaching - triggering summarization");
        return false;
    }
    return true;
}
